import React, { useState, useEffect } from 'react';
import './ApplicationForm.css';

const ApplicationForm = ({ step, onNext, onBack, formData }) => {
    const [currentFormData, setCurrentFormData] = useState({});
    const [errors, setErrors] = useState({});

    // Load existing data when step changes
    useEffect(() => {
        switch (step) {
            case 0:
                setCurrentFormData(formData.personalInfo || {});
                break;
            case 1:
                setCurrentFormData(formData.educationInfo || {});
                break;
            case 2:
                setCurrentFormData(formData.courseSelection || {});
                break;
            case 3:
                setCurrentFormData(formData.additionalInfo || {});
                break;
            default:
                setCurrentFormData({});
        }
    }, [step, formData]);

    const handleChange = (e) => {
        const { id, value, type, checked } = e.target;
        setCurrentFormData({
            ...currentFormData,
            [id]: type === 'checkbox' ? checked : value
        });

        // Clear error when user fixes a field
        if (errors[id]) {
            setErrors({
                ...errors,
                [id]: null
            });
        }
    };

    const validate = () => {
        const newErrors = {};
        const requiredFields = getRequiredFields();

        requiredFields.forEach(field => {
            if (!currentFormData[field]) {
                newErrors[field] = 'This field is required';
            }
        });

        if (step === 0 && currentFormData.email && !/\S+@\S+\.\S+/.test(currentFormData.email)) {
            newErrors.email = 'Please enter a valid email address';
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const getRequiredFields = () => {
        switch (step) {
            case 0: // Personal Information
                return ['fullName', 'email', 'phone', 'dateOfBirth'];
            case 1: // Education Background
                return ['highestEducation'];
            case 2: // Course Selection
                return ['course', 'startDate'];
            case 3: // Additional Information
                return ['howDidYouHear'];
            default:
                return [];
        }
    };

    const handleSubmit = (e) => {
        e.preventDefault();

        if (validate()) {
            onNext(currentFormData);
        }
    };

    // Render different form fields based on the current step
    const renderFormFields = () => {
        switch (step) {
            case 0:
                return (
                    <>
                        <div className="form-step-title">Personal Information</div>
                        <p className="form-step-description">
                            Tell us about yourself so we can get to know you better.
                        </p>

                        <div className="form-row">
                            <div className="form-group">
                                <input
                                    type="text"
                                    id="fullName"
                                    value={currentFormData.fullName || ''}
                                    onChange={handleChange}
                                    placeholder=" "
                                    style={{"--i": 1}}
                                />
                                <label htmlFor="fullName">Full Name *</label>
                                {errors.fullName && <div className="error-message">{errors.fullName}</div>}
                            </div>

                            <div className="form-group">
                                <input
                                    type="email"
                                    id="email"
                                    value={currentFormData.email || ''}
                                    onChange={handleChange}
                                    placeholder=" "
                                    style={{"--i": 2}}
                                />
                                <label htmlFor="email">Email Address *</label>
                                {errors.email && <div className="error-message">{errors.email}</div>}
                            </div>
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                <input
                                    type="tel"
                                    id="phone"
                                    value={currentFormData.phone || ''}
                                    onChange={handleChange}
                                    placeholder=" "
                                    style={{"--i": 3}}
                                />
                                <label htmlFor="phone">Phone Number *</label>
                                {errors.phone && <div className="error-message">{errors.phone}</div>}
                            </div>

                            <div className="form-group">
                                <input
                                    type="date"
                                    id="dateOfBirth"
                                    value={currentFormData.dateOfBirth || ''}
                                    onChange={handleChange}
                                    placeholder=" "
                                    style={{"--i": 4}}
                                />
                                <label htmlFor="dateOfBirth">Date of Birth *</label>
                                {errors.dateOfBirth && <div className="error-message">{errors.dateOfBirth}</div>}
                            </div>
                        </div>

                        <div className="form-group">
                            <input
                                type="text"
                                id="address"
                                value={currentFormData.address || ''}
                                onChange={handleChange}
                                placeholder=" "
                                style={{"--i": 5}}
                            />
                            <label htmlFor="address">Address</label>
                        </div>
                    </>
                );

            case 1:
                return (
                    <>
                        <div className="form-step-title">Educational Background</div>
                        <p className="form-step-description">
                            Tell us about your educational experience and qualifications.
                        </p>

                        <div className="form-group">
                            <select
                                id="highestEducation"
                                value={currentFormData.highestEducation || ''}
                                onChange={handleChange}
                                placeholder=" "
                                style={{"--i": 1}}
                            >
                                <option value=""></option>
                                <option value="highSchool">High School</option>
                                <option value="associates">Associate's Degree</option>
                                <option value="bachelors">Bachelor's Degree</option>
                                <option value="masters">Master's Degree</option>
                                <option value="doctorate">Doctorate</option>
                                <option value="other">Other</option>
                            </select>
                            <label htmlFor="highestEducation">Highest Level of Education *</label>
                            {errors.highestEducation && <div className="error-message">{errors.highestEducation}</div>}
                        </div>

                        <div className="form-group">
                            <input
                                type="text"
                                id="schoolName"
                                value={currentFormData.schoolName || ''}
                                onChange={handleChange}
                                placeholder=" "
                                style={{"--i": 2}}
                            />
                            <label htmlFor="schoolName">Institution Name</label>
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                <input
                                    type="text"
                                    id="fieldOfStudy"
                                    value={currentFormData.fieldOfStudy || ''}
                                    onChange={handleChange}
                                    placeholder=" "
                                    style={{"--i": 3}}
                                />
                                <label htmlFor="fieldOfStudy">Field of Study</label>
                            </div>

                            <div className="form-group">
                                <input
                                    type="text"
                                    id="graduationYear"
                                    value={currentFormData.graduationYear || ''}
                                    onChange={handleChange}
                                    placeholder=" "
                                    style={{"--i": 4}}
                                />
                                <label htmlFor="graduationYear">Graduation Year</label>
                            </div>
                        </div>

                        <div className="form-group">
                            <textarea
                                id="relevantExperience"
                                value={currentFormData.relevantExperience || ''}
                                onChange={handleChange}
                                rows="4"
                                placeholder=" "
                                style={{"--i": 5}}
                            ></textarea>
                            <label htmlFor="relevantExperience">Relevant Experience</label>
                        </div>
                    </>
                );

            case 2:
                return (
                    <>
                        <div className="form-step-title">Program Selection</div>
                        <p className="form-step-description">
                            Select the program and schedule that best fits your needs.
                        </p>

                        <div className="form-group">
                            <select
                                id="course"
                                value={currentFormData.course || ''}
                                onChange={handleChange}
                                style={{"--i": 1}}
                            >
                                <option value=""></option>
                                <option value="webDevelopment">Web Development</option>
                                <option value="dataScience">Data Science & Analytics</option>
                                <option value="cybersecurity">Cybersecurity</option>
                                <option value="cloudComputing">Cloud Computing</option>
                                <option value="aiMachineLearning">AI & Machine Learning</option>
                            </select>
                            <label htmlFor="course">Desired Program *</label>
                            {errors.course && <div className="error-message">{errors.course}</div>}
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                <select
                                    id="studyFormat"
                                    value={currentFormData.studyFormat || ''}
                                    onChange={handleChange}
                                    style={{"--i": 2}}
                                >
                                    <option value=""></option>
                                    <option value="fullTime">Full-Time</option>
                                    <option value="partTime">Part-Time</option>
                                    <option value="weekend">Weekend</option>
                                </select>
                                <label htmlFor="studyFormat">Study Format</label>
                            </div>

                            <div className="form-group">
                                <select
                                    id="startDate"
                                    value={currentFormData.startDate || ''}
                                    onChange={handleChange}
                                    style={{"--i": 3}}
                                >
                                    <option value=""></option>
                                    <option value="summer2025">Summer 2025 (June)</option>
                                    <option value="fall2025">Fall 2025 (September)</option>
                                    <option value="winter2026">Winter 2026 (January)</option>
                                </select>
                                <label htmlFor="startDate">Desired Start Date *</label>
                                {errors.startDate && <div className="error-message">{errors.startDate}</div>}
                            </div>
                        </div>

                        <div className="form-group">
                            <textarea
                                id="programInterest"
                                value={currentFormData.programInterest || ''}
                                onChange={handleChange}
                                rows="4"
                                placeholder=" "
                                style={{"--i": 4}}
                            ></textarea>
                            <label htmlFor="programInterest">Why are you interested in this program?</label>
                        </div>
                    </>
                );

            case 3:
                return (
                    <>
                        <div className="form-step-title">Additional Information</div>
                        <p className="form-step-description">
                            Help us understand your goals and how we can better assist you.
                        </p>

                        <div className="form-group">
                            <select
                                id="howDidYouHear"
                                value={currentFormData.howDidYouHear || ''}
                                onChange={handleChange}
                                style={{"--i": 1}}
                            >
                                <option value=""></option>
                                <option value="searchEngine">Search Engine</option>
                                <option value="socialMedia">Social Media</option>
                                <option value="friend">Friend or Family</option>
                                <option value="advertisement">Advertisement</option>
                                <option value="event">Event or Career Fair</option>
                                <option value="other">Other</option>
                            </select>
                            <label htmlFor="howDidYouHear">How did you hear about us? *</label>
                            {errors.howDidYouHear && <div className="error-message">{errors.howDidYouHear}</div>}
                        </div>

                        <div className="form-group">
                            <textarea
                                id="careerGoals"
                                value={currentFormData.careerGoals || ''}
                                onChange={handleChange}
                                rows="4"
                                placeholder=" "
                                style={{"--i": 2}}
                            ></textarea>
                            <label htmlFor="careerGoals">What are your career goals?</label>
                        </div>

                        <div className="form-group">
                            <textarea
                                id="questions"
                                value={currentFormData.questions || ''}
                                onChange={handleChange}
                                rows="4"
                                placeholder=" "
                                style={{"--i": 3}}
                            ></textarea>
                            <label htmlFor="questions">Questions or Comments</label>
                        </div>

                        <div className="form-checkbox" style={{"--i": 4}}>
                            <input
                                type="checkbox"
                                id="agreeToTerms"
                                checked={currentFormData.agreeToTerms || false}
                                onChange={handleChange}
                                required
                            />
                            <label htmlFor="agreeToTerms">
                                I agree to the <a href="/terms" target="_blank" rel="noopener noreferrer">Terms & Conditions</a> and consent to Forum Information Academy processing my data.
                            </label>
                        </div>
                    </>
                );

            default:
                return <div>Unknown step</div>;
        }
    };

    return (
        <div className="application-form">
            <form onSubmit={handleSubmit}>
                {renderFormFields()}

                <div className="form-actions">
                    {step > 0 && (
                        <button 
                            type="button" 
                            className="btn btn-outline" 
                            onClick={onBack}
                        >
                            Back
                        </button>
                    )}
                    <button 
                        type="submit" 
                        className="btn btn-primary"
                        style={{"--i": 6}}
                    >
                        {step === 3 ? 'Submit Application' : 'Continue'}
                        <span className="material-icons">
                            {step === 3 ? 'send' : 'arrow_forward'}
                        </span>
                    </button>
                </div>
            </form>
        </div>
    );
};

export default ApplicationForm;
